mapper.select:
SELECT id, receipt_number, reagent_id, reagent_name, quantity, unit_price, operator_id, operator_name, receipt_time, remark FROM warehouse_receipt
AND id = #{id}
AND reagent_name LIKE CONCAT('%', #{reagentName}, '%')
AND receipt_number = #{receiptNumber}
AND operator_id = #{operatorId}
ORDER BY id DESC
